import React from 'react';
const Login = () => {
    return(
        <div className = "container">
            <div className = "row justify-content-center mt-4">
                <div className = "col-lg-5 card border-primary mt-4">
                    {/* <div className="card text-white bg-danger mb-3 " style={{"max-width":"20rem"}}> */}
                        <div className="card-header">Header</div>
                        <div className="card-body">
                            <h4 className="card-title">Danger card title</h4>
                            <div className="row">
                                <label htmlFor="staticEmail" className="col-sm-2 col-form-label">Email</label>
                                <div className="col-sm-10">
                                    <input type="text" readOnly className="form-control-plaintext" id="staticEmail" defaultValue="email@example.com" />
                                </div>
                                </div>
                        </div>
                        </div>
                {/* </div>    */}
            </div>
        </div>
    )
}

export default Login;
